using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API via HttpClient (injected through DI).
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches a resource from the external API by its identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to fetch")] string resourceId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {ResourceId}", resourceId);
        var response = await httpClient.GetAsync($"/api/resources/{resourceId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Searches the external API with a query string and returns matching results.")]
    public async Task<string> SearchApi(
        [Description("The search query")] string query,
        [Description("Maximum number of results to return")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching API for '{Query}' (max {Max})", query, maxResults);
        var response = await httpClient.GetAsync(
            $"/api/search?q={Uri.EscapeDataString(query)}&limit={maxResults}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

